using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability to the research agent.
/// Uses a simple HTTP-based approach that can be swapped for
/// Bing Search API, Google Custom Search, or any search provider.
/// </summary>
public sealed class WebSearchTool : IDisposable
{
    private readonly HttpClient _httpClient;

    public WebSearchTool()
    {
        _httpClient = new HttpClient();
        _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (compatible; research-bot)");
        _httpClient.Timeout = TimeSpan.FromSeconds(15);
    }

    [Description(
        "Searches the web for a query and returns a list of results with titles, URLs, and snippets. " +
        "Use this to find information about a research topic. Returns up to 5 results.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            // Uses DuckDuckGo Instant Answer API (no key required)
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, cancellationToken);

            if (response is null)
                return "No results found.";

            var results = new List<string>();

            // Add the abstract/answer if available
            if (!string.IsNullOrWhiteSpace(response.Abstract))
            {
                results.Add($"**Summary**: {response.Abstract}");
                if (!string.IsNullOrWhiteSpace(response.AbstractSource))
                    results.Add($"  Source: {response.AbstractSource} ({response.AbstractURL})");
            }

            if (!string.IsNullOrWhiteSpace(response.Answer))
                results.Add($"**Direct Answer**: {response.Answer}");

            // Add related topics
            if (response.RelatedTopics is { Count: > 0 })
            {
                foreach (var topic in response.RelatedTopics.Take(5))
                {
                    if (!string.IsNullOrWhiteSpace(topic.Text))
                    {
                        var entry = $"- {topic.Text}";
                        if (!string.IsNullOrWhiteSpace(topic.FirstURL))
                            entry += $"\n  URL: {topic.FirstURL}";
                        results.Add(entry);
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing the search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description(
        "Fetches the text content of a specific web page URL. " +
        "Use this after searching to read the full content of a promising result.")]
    public async Task<string> FetchPage(
        [Description("The full URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var response = await _httpClient.GetAsync(url, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);

            // Strip HTML tags for a rough plain-text extraction
            var text = StripHtml(html);

            // Truncate to avoid blowing up the context window
            const int maxLength = 3000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated]";

            return $"Content from {url}:\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = System.Text.RegularExpressions.Regex.Replace(
            html, @"<(script|style)[^>]*>.*?</\1>", "", System.Text.RegularExpressions.RegexOptions.Singleline);
        // Remove HTML tags
        html = System.Text.RegularExpressions.Regex.Replace(html, @"<[^>]+>", " ");
        // Decode common entities
        html = System.Net.WebUtility.HtmlDecode(html);
        // Collapse whitespace
        html = System.Text.RegularExpressions.Regex.Replace(html, @"\s+", " ").Trim();
        return html;
    }

    public void Dispose() => _httpClient.Dispose();
}

// DuckDuckGo Instant Answer API response model
file sealed class DuckDuckGoResponse
{
    [JsonPropertyName("Abstract")]
    public string? Abstract { get; set; }

    [JsonPropertyName("AbstractSource")]
    public string? AbstractSource { get; set; }

    [JsonPropertyName("AbstractURL")]
    public string? AbstractURL { get; set; }

    [JsonPropertyName("Answer")]
    public string? Answer { get; set; }

    [JsonPropertyName("RelatedTopics")]
    public List<RelatedTopic>? RelatedTopics { get; set; }
}

file sealed class RelatedTopic
{
    [JsonPropertyName("Text")]
    public string? Text { get; set; }

    [JsonPropertyName("FirstURL")]
    public string? FirstURL { get; set; }
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can collect, organize,
/// and retrieve research findings across multiple search iterations.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description(
        "Saves a research note with a title and detailed content. " +
        "Use this to record key findings, facts, or quotes from web searches. " +
        "Each note should capture one distinct piece of information.")]
    public string AddNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content, findings, or facts to record")] string content,
        [Description("The source URL where this information was found, if any")] string? sourceUrl = null)
    {
        var note = new Note(
            Id: _notes.Count + 1,
            Title: title,
            Content: content,
            SourceUrl: sourceUrl,
            CreatedAt: DateTime.UtcNow);

        _notes.Add(note);
