using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability so the agent can collect, organize,
/// and retrieve research findings across multiple search iterations.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description(
        "Saves a research note with a title and detailed content. " +
        "Use this to record key findings, facts, or quotes from web searches. " +
        "Each note should capture one distinct piece of information.")]
    public string AddNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content, findings, or facts to record")] string content,
        [Description("The source URL where this information was found, if any")] string? sourceUrl = null)
    {
        var note = new Note(
            Id: _notes.Count + 1,
            Title: title,
            Content: content,
            SourceUrl: sourceUrl,
            CreatedAt: DateTime.UtcNow);

        _notes.Add(note);
        return $"Note #{note.Id} saved: \"{title}\"";
    }

    [Description(
        "Retrieves all saved research notes. " +
        "Use this before writing a summary to review everything collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== {_notes.Count} Research Notes ===\n");

        foreach (var note in _notes)
        {
            sb.AppendLine($"--- Note #{note.Id}: {note.Title} ---");
            sb.AppendLine(note.Content);
            if (!string.IsNullOrWhiteSpace(note.SourceUrl))
                sb.AppendLine($"Source: {note.SourceUrl}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description(
        "Deletes a previously saved note by its ID number. " +
        "Use this to remove irrelevant or duplicate notes.")]
    public string DeleteNote(
        [Description("The ID number of the note to delete")] int noteId)
    {
        var note = _notes.FirstOrDefault(n => n.Id == noteId);
        if (note is null)
            return $"Note #{noteId} not found.";

        _notes.Remove(note);
        return $"Note #{noteId} (\"{note.Title}\") deleted.";
    }
}

public sealed record Note(
    int Id,
    string Title,
    string Content,
    string? SourceUrl,
    DateTime CreatedAt);

