using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run the research agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build IChatClient via MEAI ---
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, new ApiKeyCredential(apiKey))
    .AsIChatClient();

// --- Create tools ---
using var webSearch = new WebSearchTool();
var noteTool = new NoteTool();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchPage),
    AIFunctionFactory.Create(noteTool.AddNote),
    AIFunctionFactory.Create(noteTool.GetNotes),
    AIFunctionFactory.Create(noteTool.DeleteNote),
};

// --- Create agent ---
var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Instructions = """
        You are a thorough research agent. Your goal is to research a topic by:

        1. SEARCH: Use SearchWeb to find relevant information about the topic.
           Run multiple searches with different queries to get comprehensive coverage.

        2. READ: Use FetchPage to read promising web pages from the search results.

        3. TAKE NOTES: Use AddNote to save key findings as you go.
           Each note should capture one distinct fact or insight with its source.

        4. REVIEW: Use GetNotes to review all collected notes before summarizing.

        5. SUMMARIZE: After gathering enough information (at least 3-5 notes),
           write a well-structured summary of your findings. Include:
           - An overview of the topic
           - Key facts and details
           - Different perspectives if applicable
           - Sources for the information

        Be systematic: search, read, note, then summarize. Do not fabricate information.
        Only include facts you found through your tools.
        """,
    Tools = tools,
};

var agent = new ChatClientAgent(chatClient, agentOptions);
var session = await agent.CreateSessionAsync();

// --- Run options with guardrails ---
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

// --- Get topic from user ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine("─────────────────────────────────────────");
Console.WriteLine();

// --- Stream agent response ---
await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (update.StreamingUpdate?.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine();
Console.WriteLine();

// --- Print collected notes ---
if (noteTool.Notes.Count > 0)
{
    Console.WriteLine("─────────────────────────────────────────");
    Console.WriteLine($"Research Notes Collected: {noteTool.Notes.Count}");
    Console.WriteLine("─────────────────────────────────────────");
    foreach (var note in noteTool.Notes)
    {
        Console.WriteLine($"  [{note.Id}] {note.Title}");
        if (!string.IsNullOrWhiteSpace(note.SourceUrl))
            Console.WriteLine($"      Source: {note.SourceUrl}");
    }
}

